3_real_world_example.code:
const player1 = { name: 'Mario', score: 0 };

//  MISTAKE: This does not copy the object!
const player2 = player1;

// We try to change player2...
player2.name = 'Luigi';
player2.score = 100;

// But player1 was mutated too!
console.log(player1.name); // 'Luigi'
console.log(player1.score); // 100

